    const emaFast = ema(close, fastPeriod);
    const emaSlow = ema(close, slowPeriod);
    const macdLine = emaFast.map((fast, i) => {
      const slow = emaSlow[i];
      return (Number.isFinite(fast) && Number.isFinite(slow)) ? fast - slow : NaN;
    });
    const signalLine = ema(macdLine, signalPeriod);
    const histogram = macdLine.map((macd, i) => {
      const signal = signalLine[i];
      return (Number.isFinite(macd) && Number.isFinite(signal)) ? macd - signal : NaN;
    });
    return { macdLine, signalLine, histogram };
  };

  // ===== OBV (On-Balance Volume) calculation =====
  const calculateOBV = (close, volume) => {
    const obv = new Array(close.length).fill(0);
    if (close.length < 2) return obv;
    obv[0] = Number(volume[0]) || 0;
    for (let i = 1; i < close.length; i++) {
      const c = Number(close[i]);
      const cp = Number(close[i - 1]);
      const v = Number(volume[i]) || 0;
      if (Number.isFinite(c) && Number.isFinite(cp)) {
        if (c > cp) {
          obv[i] = obv[i - 1] + v;
        } else if (c < cp) {
          obv[i] = obv[i - 1] - v;
        } else {
          obv[i] = obv[i - 1];
        }
      } else {
        obv[i] = obv[i - 1];
      }
    }
    return obv;
  };

  // ===== Divergence detection =====
  const detectBearishDivergence = (prices, indicator, lookback = 10) => {
    if (prices.length < lookback + 2 || indicator.length < lookback + 2) return false;
    const n = prices.length;

    // Find recent peaks in price (last 2 peaks within lookback period)
    const pricePeaks = [];
    for (let i = n - lookback; i < n - 1; i++) {
      if (i <= 0) continue;
      const curr = Number(prices[i]);
      const prev = Number(prices[i - 1]);
      const next = i + 1 < n ? Number(prices[i + 1]) : NaN;
      if (Number.isFinite(curr) && Number.isFinite(prev) && Number.isFinite(next)) {
        if (curr > prev && curr >= next) {
          pricePeaks.push({ idx: i, val: curr });
        }
      }
    }

    if (pricePeaks.length < 2) return false;

    // Check if price made higher high but indicator made lower high
    const lastPricePeak = pricePeaks[pricePeaks.length - 1];
    const prevPricePeak = pricePeaks[pricePeaks.length - 2];

    const lastIndicatorVal = Number(indicator[lastPricePeak.idx]);
    const prevIndicatorVal = Number(indicator[prevPricePeak.idx]);

    if (!Number.isFinite(lastIndicatorVal) || !Number.isFinite(prevIndicatorVal)) return false;

    // Bearish divergence: price higher high + indicator lower high
    const priceHigherHigh = lastPricePeak.val > prevPricePeak.val;
    const indicatorLowerHigh = lastIndicatorVal < prevIndicatorVal;

    return priceHigherHigh && indicatorLowerHigh;
  };

