    let cumulV = 0;

    for (let i = 0; i < prices.length; i++) {
      const p = Number(prices[i]);
      const v = Number(volumes[i]);
      if (Number.isFinite(p) && Number.isFinite(v) && v >= 0) {
        cumulPV += p * v;
        cumulV += v;
        vwap[i] = cumulV > 0 ? cumulPV / cumulV : NaN;
      } else if (i > 0) {
        vwap[i] = vwap[i - 1];
